const stdout = $input.first().json.stdout || '';
const stderr = $input.first().json.stderr || '';
const triggerData = $('Called by Receiver').first().json;
const issueId = triggerData.issueId || '';
const summary = triggerData.summary || '';

const MAX_SESSION_COST = 5;

const output = stdout.trim() || stderr.trim();

let result, sessionId, isEmpty, costEur = 0, numTurns = 0, durationMs = 0;
let lastModel = '';
let toolCallCount = 0, toolErrorCount = 0, totalInputTokens = 0, totalOutputTokens = 0;
let totalCacheWrite = 0, totalCacheRead = 0;

const jsonlPath = '/tmp/claude-run-' + issueId + '.jsonl';

try {
  const parsed = JSON.parse(output);
  result = parsed.result || '';
  sessionId = parsed.session_id || '';
  const USD_TO_EUR = 0.92;
  costEur = (parsed.cost_usd || 0) * USD_TO_EUR;
  numTurns = parsed.num_turns || 0;
  durationMs = parsed.duration_ms || 0;
  isEmpty = !result;
  // Model + tokens extracted by Wait for Claude from JSONL before cleanup
  lastModel = parsed.model || '';
  totalInputTokens = parsed.input_tokens || 0;
  totalOutputTokens = parsed.output_tokens || 0;
  totalCacheWrite = parsed.cache_write || 0;
  totalCacheRead = parsed.cache_read || 0;
  toolCallCount = parsed.tool_calls || 0;
  toolErrorCount = parsed.tool_errors || 0;
} catch (e) {
  // stream-json mode: extract result + cost from JSONL file
  try {
    const fs = require('fs');
    const lines = fs.readFileSync(jsonlPath, 'utf8').trim().split('\n');

    let lastText = '';
    sessionId = '';
    numTurns = 0;

    for (const line of lines) {
      try {
        const d = JSON.parse(line);
        if (d.type === 'system' && d.subtype === 'init' && d.session_id) {
          sessionId = d.session_id;
        }
        if (d.type === 'assistant') {
          numTurns++;
          const msg = d.message || {};
          if (msg.model) lastModel = msg.model;
          const content = msg.content || [];
          for (const block of content) {
            if (block.type === 'text' && block.text) lastText = block.text;
            if (block.type === 'tool_use') toolCallCount++;
          }
          const usage = msg.usage || {};
          totalInputTokens += usage.input_tokens || 0;
          totalOutputTokens += usage.output_tokens || 0;
          totalCacheWrite += usage.cache_creation_input_tokens || 0;
          totalCacheRead += usage.cache_read_input_tokens || 0;
        }
        if (d.type === 'user') {
          const msg = d.message || {};
          const content = msg.content || [];
          for (const block of content) {
            if (block.type === 'tool_result' && block.is_error) toolErrorCount++;
          }
        }
      } catch (lineErr) {}
    }

    result = lastText;
    isEmpty = !result;

    // Opus 4.6 pricing (per 1M tokens)
    const costUsd = (totalInputTokens * 15.0 + totalOutputTokens * 75.0 +
                     totalCacheWrite * 18.75 + totalCacheRead * 1.50) / 1000000;
    costEur = costUsd * 0.92;

  } catch (fsErr) {
    if (!output) { result = ''; isEmpty = true; }
    else { result = 'Error: ' + output.substring(0, 1000); isEmpty = false; }
    sessionId = '';
  }
}

const hasValidSession = !!(sessionId && issueId);

const costExceeded = costEur > MAX_SESSION_COST;
const toolCallLimitExceeded = toolCallCount > 75;
if (toolCallLimitExceeded) {
  result = '\u26a0\ufe0f TOOL CALL LIMIT: ' + toolCallCount + ' tool calls (>75 limit). Investigation may be over-scoped.\n\n' + result;
}
if (costExceeded) {
  result = '\u26a0\ufe0f COST CEILING EXCEEDED (\u20ac' + costEur.toFixed(2).replace('.', ',') + ' > \u20ac' + MAX_SESSION_COST + ' limit)\n\n' + result;
}

const confidenceMatch = result.match(/CONFIDENCE:\s*(\d\.\d+|\d)\s*[\u2013\u2014\-]\s*(.+?)(?:\n|$)/i);
const confidence = confidenceMatch ? parseFloat(confidenceMatch[1]) : -1;
const confidenceReason = confidenceMatch ? confidenceMatch[2].trim() : '';
const hasConfidence = confidence >= 0;

const prefix = issueId.split('-')[0] || '';
const isInfra = prefix === 'IFRNLLEI01PRD' || prefix === 'IFRGRSKG01PRD';
const hasApprovalGate = /awaiting approval|waiting for.*approval|reply.*approved|\[POLL\]/i.test(result);
const missingApprovalGate = isInfra && !isEmpty && !hasApprovalGate && result.length > 200;

let inconsistentReasoning = false;
if (hasConfidence && !isEmpty) {
  const hedgingWords = (result.match(/\b(might|possibly|unclear|uncertain|unsure|maybe|perhaps|not sure)\b/gi) || []).length;
  const actionWords = (result.match(/\b(restart|apply|execute|deploy|fix|change|modify|update|remove|delete)\b/gi) || []).length;
  if (confidence >= 0.8 && hedgingWords >= 3) inconsistentReasoning = true;
  if (confidence < 0.5 && actionWords >= 3 && !/\bstop\b.*\bwait\b/i.test(result)) inconsistentReasoning = true;
}

const hasReactStructure = /THOUGHT:|SYNTHESIS:|OBSERVATION:/i.test(result);
const missingReactStructure = isInfra && !isEmpty && result.length > 500 && !hasReactStructure;

const validationWarnings = [];
if (!hasConfidence && !isEmpty && result.length > 100) validationWarnings.push('missing_confidence');
if (missingApprovalGate) validationWarnings.push('missing_approval_gate');
if (inconsistentReasoning) validationWarnings.push('inconsistent_reasoning');
if (missingReactStructure) validationWarnings.push('missing_react_structure');

let promptVariant = '';
try { promptVariant = $('Build Prompt').first().json.promptVariant || ''; } catch(e) {}

return [{ json: {
  result, sessionId, issueId, summary, hasValidSession, isEmpty,
  confidence, confidenceReason, hasConfidence,
  hasApprovalGate, missingApprovalGate,
  inconsistentReasoning, missingReactStructure,
  validationWarnings: validationWarnings.join(','),
  hasWarnings: validationWarnings.length > 0,
  costEur, numTurns, durationMs, costExceeded,
  toolCallCount, toolErrorCount, totalInputTokens, totalOutputTokens,
  toolCallLimitExceeded,
  promptVariant,
  model: lastModel || '',
  totalInputTokens: totalInputTokens || 0,
  totalOutputTokens: totalOutputTokens || 0,
  totalCacheWrite: totalCacheWrite || 0,
  totalCacheRead: totalCacheRead || 0
