const parts = ['FINAL VALIDATION (attempt 2 of 2) \u2014 your response will be posted regardless after this:'];
if (warnings.includes('missing_confidence')) {
  parts.push('MANDATORY: Add this exact line at the END of your response:\nCONFIDENCE: 0.X \u2014 <your one-line reasoning>\nReplace 0.X with your actual confidence (0.0-1.0).');
