const stdout = $input.first().json.stdout || '';
const orig = $('Parse Retry Response').first().json;
const output = stdout.trim();
let result;
try { result = JSON.parse(output).result || ''; } catch(e) { result = output ? output.substring(0,2000) : ''; }
const finalResult = result || orig.result;
const cm = finalResult.match(/CONFIDENCE:\s*(\d\.\d+|\d)\s*[\u2014-]\s*(.+?)(?:\n|$)/i);

const issueId = orig.issueId || '';
const prefix = issueId.split('-')[0] || '';
const isInfra = prefix === 'IFRNLLEI01PRD' || prefix === 'IFRGRSKG01PRD';
const hasApprovalGate = /awaiting approval|waiting for.*approval|reply.*approved/i.test(finalResult);
const stillMissingConf = !cm && finalResult.length > 100;
const stillMissingApproval = isInfra && finalResult.length > 200 && !hasApprovalGate;
const retriedWithWarnings = stillMissingConf || stillMissingApproval;

return [{json:{
  result: finalResult,
  sessionId: orig.sessionId,
  issueId: orig.issueId,
  summary: orig.summary,
  hasValidSession: orig.hasValidSession,
  isEmpty: !finalResult,
  confidence: cm ? parseFloat(cm[1]) : -1,
  confidenceReason: cm ? cm[2].trim() : '',
  hasConfidence: !!cm,
  retryCount: 2,
  retriedWithWarnings,
  validationWarnings: '',
  hasWarnings: false,
  costEur: orig.costEur || 0,
  numTurns: orig.numTurns || 0,
  durationMs: orig.durationMs || 0,
  durationSeconds: orig.durationSeconds || 0,
  model: orig.model || '',
  totalInputTokens: orig.totalInputTokens || 0,
  totalOutputTokens: orig.totalOutputTokens || 0,
  totalCacheWrite: orig.totalCacheWrite || 0,
