}}];

const issueId = $('Called by Receiver').first().json.issueId || 'unknown';
const prefix = issueId.split('-')[0];
const slot = (prefix === 'IFRNLLEI01PRD') ? 'infra-nl'
           : (prefix === 'IFRGRSKG01PRD') ? 'infra-gr'
           : (prefix === 'CUBEOS') ? 'cubeos'
           : (prefix === 'MESHSAT') ? 'meshsat'
           : 'dev';
const lockFile = 'gateway.lock.' + slot;
return [{ json: { slot, lockFile } }];

const data = $('Prepare Result').first().json;
const confidence = data.confidence !== undefined ? data.confidence : -1;
const issueId = data.issueId || '';
const prefix = issueId.split('-')[0] || '';
const isInfra = prefix === 'IFRNLLEI01PRD' || prefix === 'IFRGRSKG01PRD';
const targetRoom = data.targetRoom || '';

// Review ALL projects with low confidence, not just infra
const shouldReview = confidence >= 0 && confidence < 0.7;

if (!shouldReview) return [];

const reviewType = isInfra ? 'infrastructure' : 'development';

// NL-A2A/v1 review request envelope
const envelope = {
  protocol: 'nl-a2a/v1',
  type: 'review-request',
  from: { tier: 2, agent: 'claude-code' },
  to: { tier: 1, agent: 'openclaw' },
  issueId: issueId,
  payload: {
    reviewType: reviewType,
    confidence: confidence,
    analysisLength: (data.result || '').length,
    hasApprovalGate: data.hasApprovalGate || false,
    promptVariant: data.promptVariant || ''
  }
};

const body = '@openclaw REVIEW REQUEST (NL-A2A/v1): Verify ' + reviewType + ' analysis for ' + issueId + '.\nConfidence: ' + confidence + '.\nProtocol: Use chain-of-verification (5-step checklist). Output REVIEW_JSON with verdict.\nA2A_ENVELOPE:' + JSON.stringify(envelope);
const matrixBody = JSON.stringify({
  msgtype: 'm.text',
  body: body
});

return [{ json: { matrixBody, targetRoom, issueId } }];

// Evaluator-Optimizer: Apply Haiku screening result
const screenResult = ($input.first().json.stdout || 'PASS').trim();
const prepData = $('Should Screen?').first().json;
let matrixBody = prepData.matrixBody;

const screeningPassed = screenResult.startsWith('PASS');
const failReason = screenResult.startsWith('FAIL:') ? screenResult.substring(5).trim() : '';

if (!screeningPassed && matrixBody) {
  try {
    const parsed = JSON.parse(matrixBody);
    const banner = '\u26a0\ufe0f SCREENING: Haiku flagged this response: ' + failReason + '\n\n';
    if (parsed.body) parsed.body = banner + parsed.body;
    if (parsed.formatted_body) parsed.formatted_body = '<p><strong>\u26a0\ufe0f SCREENING:</strong> Haiku flagged: ' + failReason + '</p>' + parsed.formatted_body;
    matrixBody = JSON.stringify(parsed);
  } catch(e) {}
}

return [{ json: {
  ...prepData,
  matrixBody,
  screeningResult: screeningPassed ? 'pass' : 'fail',
  screeningReason: failReason
} }];
